query:
SELECT positionId, COUNT(*) as question_count FROM position_questions pq 
JOIN position_categories pc ON pq.categoryId = pc.id 
GROUP BY positionId ORDER BY positionId;
SELECT COUNT(*) as total_questions FROM position_questions;

